trigger.body:
	rSeq RECORD;
BEGIN

	IF AD_isTriggerEnabled() = 'N' THEN RETURN;END IF;

	IF INSERTING THEN

        SELECT * INTO rSeq FROM (
            SELECT ROW_NUMBER() OVER (ORDER BY ad_org_id DESC) rowNo, name
            FROM ad_sequence
            WHERE em_sproctm_project_seq = 'Y' AND isactive = 'Y' AND ad_org_id IN ('0', :NEW.ad_org_id)
        ) tb WHERE rowNo = 1;

        IF rSeq.rowNo IS NOT NULL THEN

            SELECT ad_sequence_doc(rSeq.name, :NEW.ad_client_id, 'Y') INTO :NEW.value;

        END IF;

	END IF;

	END SPROCTM_PROJECT_SEQUENCE_TRG
